module RegisterFile (
    input clk,
    input rst_n,
    input write_enable,
    input [1:0] write_address,
    input [1:0] read_address,
    input [15:0] write_data,
    output reg [15:0] read_data
);
    reg [15:0] memory_cells [0:3];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            memory_cells[0] <= 16'b0;
            memory_cells[1] <= 16'b0;
            memory_cells[2] <= 16'b0;
            memory_cells[3] <= 16'b0;
        end else if (write_enable) begin
            memory_cells[write_address] <= write_data;
        end
    end

    always @(*) begin
        read_data = memory_cells[read_address];
    end
endmodule
